import { useNavigate } from 'react-router-dom';
import React, { useState, useEffect } from 'react';
import { FaRocket } from "react-icons/fa";
import axios from 'axios';
import './Home.css';

function Home() {
  const [showProfile, setShowProfile] = useState(false);
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  const [stats, setStats] = useState({
    totalPredictions: 0,
    avgSalary: 0,
    bestModelAccuracy: 0
  });

  // Fetch stats
  uuseEffect(() => {
  const storedUser = localStorage.getItem("user");

  if (storedUser) {
    const userData = JSON.parse(storedUser);
    setUser(userData);

    // 🔥 FETCH USER BASED STATS
    axios.get(`http://localhost:5001/stats/${userData.email}`)
      .then(res => {
        setStats({
          totalPredictions: res.data.totalPredictions || 0,
          avgSalary: 0, // optional for now
          bestModelAccuracy: 0 // optional
        });
      })
      .catch(err => console.log(err));

  } else {
    navigate('/login');
  }
}, [navigate]);

  return (
    <div className="home-container">

      {/* NAVBAR */}
      <nav className="navbar">
        <h3>Dashboard</h3>

        <div className="right-section">
          <div
            className="profile-circle"
            onClick={() => setShowProfile(!showProfile)}
          >
            <span>{user?.name?.charAt(0) || "P"}</span>
          </div>

          {showProfile && (
            <div className="profile-card">
              <h3>Profile 👤</h3>
              <p><b>Name:</b> {user?.name}</p>
              <p><b>Email:</b> {user?.email}</p>
              <p>
              <b>Password:</b> ********
             </p>
            </div>
          )}

          <button onClick={handleLogout} className="logout-btn">
            Logout
          </button>
        </div>
      </nav>

      {/* CONTENT */}
      <div className="main-content">
        <h2>Know Your Worth, Predict With Confidence 🚀</h2>

        <button 
  className="new-prediction-btn"
  onClick={() => navigate('/predict')}
>
  <FaRocket style={{ marginRight: "8px" }} />
  New Salary Prediction
</button>

        <div className="stats-container">
          <div className="stat-card" onClick={() => navigate("/my-history")}>
            <h3>Total Predictions</h3>
            <p>{stats.totalPredictions}</p>
          </div>

          <div className="stat-card">
            <h3>Average Salary</h3>
            <p>${stats.avgSalary}</p>
          </div>

          <div className="stat-card">
            <h3>Best Model Accuracy</h3>
            <p>{stats.bestModelAccuracy}%</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
